        }
      munmap_chunk (p);// 跳转主线3-&gt;分支1-释放mmap内存
    }
  else
    {
      MAYBE_INIT_TCACHE ();// 判断TCACHE是否初始化，malloc开始之前也有同样调用

      /* 再次将内存块标记为属于库。 */
      (void)tag_region (chunk2mem (p), memsize (p));// 涉及内存标签防护机制跳过

